      new_balance = Decimal.add(current_balance, sanitized_amount)
      :ets.insert(state.table, {account_id, new_balance})
      log_transaction(state, :deposit, account_id, sanitized_amount, new_balance)
      {:reply, {:ok, new_balance}, state}
    else
